var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어서 오세요! 카페 스트레가입니다!","JPN":"いらっしゃいませ！　カフェ・ストレガへようこそ！","ENG":"Welcome to Cafe Strega!","TWN":"歡迎光臨史特雷加咖啡廳！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"에어컨 바람이 시원하군요. 몸을 식힐 수 있겠습니다.","JPN":"エアコンの風が涼しいですね。体を冷やすことができそうです。","ENG":"The air conditioning breeze feels nice. I should be able to cool down here.","TWN":"這裡的冷氣好涼快，可以讓身體降溫一下。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"안은 시원해서 다행이야. 치후유. 옷 가게인 줄 알았는데, 카페일 줄은 몰랐네.","JPN":"中が涼しくて良かったわね、千冬。服屋かと思ったけど、カフェだったのね。","ENG":"It is good that the temperature is cool inside. I thought this would be a clothing store, but it's a cafe!","TWN":"幸好室內很涼爽。我還以為這裡是服裝店，沒想到是咖啡廳。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"<color=#ffd34c> 카페 스트레가, 이번 할로윈에도 우승인가?</color>라는 제목이었으니까요.","JPN":"<color=#ffd34c>カフェ・ストレガ、今度のハロウィンも優勝か？</color>というタイトルでしたからね。","ENG":"Well, the title did say, <color=#ffd34c>\\"Cafe Strega, Another Victory for This Year's Halloween?\\"</color>","TWN":"因為標題寫著，<color=#ffd34c> 今年萬聖節史特雷加咖啡廳也會獲勝嗎？</color>"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"아무래도 의상을 포함해 이것저것 다루는 게 아닌가 싶습니다만.","JPN":"衣装を含め、あれこれ扱っているのではと。","ENG":"I am guessing they treat various products, including costumes.","TWN":"看來這邊應有盡有，要找衣服也沒問題。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"흐음~ 정말 마녀 컨셉의 카페라, 분위기가 신선해서 더 좋지 않아?","JPN":"ふ～ん、本物の魔女コンセプトのカフェか。斬新な雰囲気もいい感じだね？","ENG":"Hmmm! A witch-themed cafe, it feels refreshing.","TWN":"嗯～真的很喜歡這個魔女主題的咖啡廳，不覺得很特別嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"예. 그렇습니다. 당주님. 마치 진짜 마녀들이 차린 카페 같군요.","JPN":"はい。同感です、当主。まるで本物の魔女が経営しているカフェのようです。","ENG":"Yes. I agree, my lady. It truly does look like a cafe set up by real witches.","TWN":"是的，堂主。感覺就像是真正的魔女開的咖啡廳一樣。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"게다가, 이곳은 시원해서 좋습니다.","JPN":"それに、涼しいのが良いです。","ENG":"Besides, I like how cool it is in here.","TWN":"而且，這裡好涼，我很喜歡。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"후훗. 그러니?","JPN":"ふふっ、そう？","ENG":"Hehe. Is that so?","TWN":"呵呵，是嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"소, 손님……! 죄송하지만, 그 뿔…… 진짠가요?","JPN":"お、お客さん……！　すみません、その角……本物ですか？","ENG":"E-excuse me...! Is that horn... real?","TWN":"這位…客人…！不好意思，請問那個角…是真的吗？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"우와! 대단하잖아?! 손님 혹시 코스 플레이어야? 아니면 진짜 요괴?","JPN":"うわ！　すごい！！　お客さん、もしかしてコスプレイヤー？　それとも本当の妖怪？","ENG":"Wow! That's amazing! Are you a cosplayer? Or a real mythical creature?","TWN":"哇！好厲害！客人你是在角色扮演嗎？還是你是真的妖怪？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"저는 그저 당주님을 지키는 호위 무사일 뿐입니다.","JPN":"私は当主をお守りしている、ただの護衛です。","ENG":"I am merely a bodyguard tasked with protecting Lady Nanahara.","TWN":"我只是堂主身邊的護衛武士而已。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"후훗. 귀여운 점원분들이시네요.","JPN":"ふふっ、かわいらしい店員さんたちですね。","ENG":"Hehe. The servers are adorable here.","TWN":"呵呵，好可愛的店員。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"두 분은 어디서 오셨나요?","JPN":"お二人はどちら様ですか？","ENG":"Where did you two come from?","TWN":"你們是從哪裡來的呢？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희는 나나하라 가문의 치나츠, 치후유라고 합니다.","JPN":"私たちは七原家の千夏と千冬と申します。","ENG":"We are Chinatsu and Chifuyu of the Nanahara family.","TWN":"我們是七原家族的千夏和千冬。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"꼬마 숙녀분들. 손님을 곤란하게 하면 안 되지~","JPN":"お嬢ちゃんたち。お客さんを困らせちゃダメよ～","ENG":"Hey little ladies. Stop bothering the customers!","TWN":"你們二個，不可以打擾客人喔～"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"너넨 얼른 다른 손님들 주문이나 받아. 예의 없게 무슨 짓이야?","JPN":"汝らは他のお客さんの注文でも受けてこい。こちらのお客さんに失礼ではないか。","ENG":"Go take the other customers' orders. You're being rude.","TWN":"還不快去幫其他客人點餐，搞什麼！有沒有禮貌！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"괜찮아요. 점원분들이 참 귀여운걸요.","JPN":"気にしないでください。店員さんがとても可愛いですね。","ENG":"It is all right. Your servers are very sweet.","TWN":"沒關係，她們很可愛。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이쪽은 깜짝 놀랐다고.","JPN":"こっちはびっくりしたぞ。","ENG":"You surprised us, you know.","TWN":"我剛嚇一跳，"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"웬 불덩이가 들어와서 환자인 줄 알았더니 멀쩡하지 뭐야?","JPN":"火の玉が入ってきて患者かと思ったら、普通にしているではないか。","ENG":"A ball of fire just walked into the cafe, and we thought it was a sick person. But she looks fine.","TWN":"想說哪來的火球，以為是病人，結果看起來很健康呢。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제 동생의 체온이 좀 높거든요.","JPN":"妹の体温は少々高いのです。","ENG":"My sister runs quite hot.","TWN":"我妹妹的體溫有點高。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"매일 에어컨을 가까이하고 있으니 걱정이랍니다.","JPN":"毎日エアコンのそばにばかりいて心配になります。","ENG":"It concerns me that she always sits near the air conditioner.","TWN":"她每天都待在冷氣旁，真讓人擔心。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"다, 당주님!","JPN":"と、当主！","ENG":"M-my lady!","TWN":"堂，堂主！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"언니라고? 흐음……","JPN":"妹？　ふーん……","ENG":"Sister? Hmm...","TWN":"你是姊姊嗎？嗯…"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};